var e=JSON.parse(`[{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"아르카데나 제국. 남부 대륙 산악 마을 <color=#ffd34c>몬테</color>.","JPN":"アルカデナ帝国。南部大陸山岳の村、<color=#ffd34c>モンテ</color>。","ENG":"The Empire of Arcadena. <color=#ffd34c>Monte</color>, a mountain village in the southern continent.","TWN":"艾爾卡特納帝國南部山區村莊<color=#ffd34c>蒙特</color>","SCN":"阿尔卡德纳帝国，南部大陆村庄， <color=#ffd34c>蒙特</color>","DEU":"The Empire of Arcadena. <color=#ffd34c>Monte</color>, a mountain village in the southern continent.","FRA":"The Empire of Arcadena. <color=#ffd34c>Monte</color>, a mountain village in the southern continent."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"구원기사단. 출정 <color=#ffd34c>하루 전</color>.","JPN":"救世騎士団。出征<color=#ffd34c>1日前</color>。","ENG":"Knights of Redemption. <color=#ffd34c>One day before</color> departure.","TWN":"救贖騎士團出征<color=#ffd34c>前一天</color>","SCN":"救赎骑士团，出征 <color=#ffd34c>前一天</color>","DEU":"Knights of Redemption. <color=#ffd34c>One day before</color> departure.","FRA":"Knights of Redemption. <color=#ffd34c>One day before</color> departure."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전하. 갑작스럽지만 괜찮으시겠습니까?","JPN":"殿下。急遽お耳に入れたいことが。よろしいでしょうか。","ENG":"Your Highness, may I have a moment to talk to you?","TWN":"殿下，方便跟殿下說句話嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그래. 무슨 일인가, 알렌 경.","JPN":"ああ。どうした、バーミンガム卿。","ENG":"You may. What is it, Sir Allen?","TWN":"說吧，艾倫卿，什麼事？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"몬테에 출정을 떠났던 선발대의 연락이 끊겼습니다.","JPN":"モンテへ出征した先発隊からの連絡が途切れました。","ENG":"We lost contact with the advance party that left for Monte.","TWN":"我們與率先出征到蒙特的先遣隊失去聯繫。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"산 정상에 있는 마을이니 물자 공급의 어려움도 있겠지만, 괴수의 규모 역시 저희 예상을 상회하는 것 같습니다.","JPN":"山の頂上にある村なので物資の供給が困難なこともありますが、怪獣の規模もまた我々の予想を上回るものと思われます。","ENG":"The village is on the top of a mountain, which makes it difficult to receive supplies, but the mass of the monsters seems to be greater than expected.","TWN":"由於村莊在山頂上，物資供給有一定的難度，但怪獸的規模似乎也超過我們的預期。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"과연, 사방이 숲인만큼 평범한 군대로는 버티는 것조차 쉽지 않은가.","JPN":"なるほど、四方が森である分、普通の軍隊では踏ん張るのにも難ありか。","ENG":"Even holding out seems tough for an ordinary army surrounded by forests.","TWN":"四周都是森林，普通的軍隊還是很難撐下去嗎？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"현재 가용 가능한 병력의 수는 어떻지?","JPN":"現在、使える兵力の数は？","ENG":"What's the number of soldiers that can participate in battle now?","TWN":"我們現在可動員的兵力有多少？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"잇따른 전투로 부상을 입은 병사가 대부분입니다.","JPN":"相続く戦闘でほとんどの兵士が負傷しています。","ENG":"Most are injured from recurring combat.","TWN":"接二連三的戰爭導致兵力多有負傷。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"고된 행군이 예상되는 만큼, 실질적으로 가용 가능한 수는 적겠군요.","JPN":"厳しい行軍が予想されますので、実質的に使える兵力数は少ないでしょう。","ENG":"An arduous march is ahead of us, which means there will be fewer soldiers that will be available.","TWN":"考慮到這趟征途不易，可動員的兵力可能相當有限。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"연회도 앞두고 있으니 말이야. 이런 시기에 사상자가 늘었다간 사기 또한 누그러질 거다.","JPN":"宴も控えているからな。このような時期に死傷者が増えると士気も下がる。","ENG":"Not to mention the banquet will be held soon. It will be bad for morale if we lose more people at a time like this.","TWN":"慶功宴在即，若是此時再增加死傷人數，恐怕會影響士氣。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"움직인다면 소수 정예. 인가….","JPN":"動くなら少数精鋭、か……","ENG":"So we need a few good men to advance...","TWN":"還是派少數精銳…"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"알렌. 루크레시아와 샬롯을 부르도록. 몬테에는 평민을 포함한 네 명이서 움직인다.","JPN":"アレン。ルクレシアとシャーロットを呼べ。モンテには平民を含めた4人で動く。","ENG":"Allen. Call for Lucrecia and Carlota. I'll take them and the peasant to go forth.","TWN":"艾倫，把露可蕾西亞和夏洛特叫來。再加上我和平民，就我們四個去蒙特。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"내가 없는 동안의 지휘권은 경에게 맡기지.","JPN":"私がいない間、指揮権は卿に任せよう。","ENG":"I'll leave you in charge while I am absent.","TWN":"我不在的時候，指揮權就交給你。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전하께서 직접 움직이실 필요는 없습니다.","JPN":"殿下が自ら動かれるまでもございません。","ENG":"There is no need for you to go yourself, Your Highness.","TWN":"殿下無須親自前往。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"제게 일러두신다면 병력을 이끌고 가 처리하겠습니다.","JPN":"私にご指示くだされば、兵力を率いて処理して参ります。","ENG":"Give the orders, and I shall take some soldiers to take care of the matter.","TWN":"只要殿下一聲令下，我就立刻帶兵前往。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"무릇 군주라면 모범을 보여야지 않겠나. 제국의 황태자가 병사들만 움직일 수는 없지.","JPN":"君主たるもの、手本を見せるべきではないか。帝国の皇太子が兵士だけに頼るわけにもいくまい。","ENG":"A ruler must set an example for his subjects. As the crown prince of the Empire, I cannot sit idle while the soldiers offer their lives to our cause.","TWN":"身為一國之君理當以身作則。帝國的皇太子怎麼可以光是使喚士兵們，自己卻躲在安樂窩裡呢？"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"연회까지 시간도 없으니, 가능한 한 신속하게 처리하고 오겠네.","JPN":"宴まで時間もない、できるだけ速やかに処理して来よう。","ENG":"We do not have much time until the banquet, so I shall make haste.","TWN":"距離慶功宴沒剩多少時間，我會盡速處理完畢回來。"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"narration","speaker":null,"text":{"KOREA":"…그래서.","JPN":"……で。","ENG":"...So.","TWN":"意思是…"},"stage":{"bg":"CHURCH","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L35_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"고작 넷이서 움직인다는 겁니까? 선발대가 전멸했을지도 모르는 위험한 장소를?","JPN":"たった4人で動くということですか？　先発隊が全滅したかもしれない、危険な場所で？","ENG":"You wish to enter a perilous area, where the advance party might have been wiped out, with just four people?","TWN":"就我們四個人嗎？目的地是先遣隊或許已經全軍覆沒的危險地方？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"허세가 심하시군요, 전하.","JPN":"虚勢を張るにも程度というものがあります、殿下。","ENG":"Very self-assured, Your Highness.","TWN":"殿下會不會太不知輕重？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"괴수와의 싸움을 넘어 부상당한 주민들까지 보살피기엔 저희만으로는 부족합니다.","JPN":"怪獣との戦いだけでなく怪我をした住民まで看るには、この人数では足りません。","ENG":"We won't be enough to fight the monsters, much less take care of the injured villagers.","TWN":"還要照顧那些和怪獸戰鬥時受傷的百姓，光靠我們四個是不夠的。"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HOLY_KNIGHT_NULL_NULL","text":{"KOREA":"굳이 다른 병력들을 내버려 두고 움직일 필요는 없습니다.","JPN":"他の兵力を差し置いて、あえて私たちが動く必要はないように思います。","ENG":"There is no need for us to move when there are other soldiers available.","TWN":"有需要放著其他的兵力不用，四個人硬上嗎？"},"stage":{"bg":"FOREST_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};